        if (result.length > 0) {
          view.dispatch({
            changes: {
              from: result[0].from,
              to: result[0].to,
              insert: pastedData,
            },
            annotations: Transaction.userEvent.of(`input.paste.smart`),
          });
        }
      }
    },
  });

