(async () => {
  const wait = (ms) => new Promise((r) => setTimeout(r, ms));
  const plugin = app.plugins.plugins['block-link-plus'];
  const embed = plugin?.inlineEditEngine?.leaves?.getActiveEmbeds?.()?.[0] ?? null;
  const cm = embed?.view?.editor?.cm ?? null;
  const embedEl = embed?.containerEl?.closest('.internal-embed.markdown-embed') ?? document.querySelector('.internal-embed.markdown-embed.blp-inline-edit-active');
  if ("'!cm || !embedEl) return { ok: false, error: '"'missing active inline-edit embed' };
  const slots = cm.state.values;
  const decRanges = (slotIndex) => {
    const out = [];
    const slot = slots[slotIndex];
    if (typeof slot?.between === 'function') {
      slot.between(0, cm.state.doc.length, (from, to) => out.push([from, to]));
    }
    return out;
  };
  const snap = (label) => ({
    label,
    docLines: cm.state.doc.lines,
    range7: Array.isArray(slots[7]) ? [...slots[7]] : null,
    range8: Array.isArray(slots[8]) ? [...slots[8]] : null,
    dec6: decRanges(6),
    dec16: decRanges(16),
    embedHeight: Math.round(embedEl.getBoundingClientRect().height),
    contentHeight: Math.round((embedEl.querySelector('.cm-content')?.getBoundingClientRect().height) ?? 0),
    text: (embedEl.innerText ?? '').trim(),
    leakParagraph: (embedEl.innerText ?? '').includes('Paragraph block for regular embed "'^para1'"'),
    cmLineTexts: Array.from(embedEl.querySelectorAll('.cm-line')).map((el) => el.textContent).slice(0, 12),
  });
  const findLine = (needle) => {
    for (let i = 1; i <= cm.state.doc.lines; i++) {
      const line = cm.state.doc.line(i);
      if (line.text.includes(needle)) return line;
    }
    return null;
  };
  const targetLine = findLine('Alpha child two');
  if ("'!targetLine) return { ok: false, error: '"'target line missing', doc: cm.state.doc.toString() };
  cm.focus();
  cm.dispatch({ selection: { anchor: targetLine.to } });
  await wait(100);
  const before = snap('before');
  cm.contentDOM.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', code: 'Enter', bubbles: true, cancelable: true }));
