(async () => {
  const wait = (ms) => new Promise((r) => setTimeout(r, ms));
  const waitFor = async (fn, { timeoutMs = 15000, stepMs = 50 } = {}) => {
    const t0 = Date.now();
    while (Date.now() - t0 < timeoutMs) {
      const v = await fn();
      if (v) return v;
      await wait(stepMs);
    }
    return null;
  };
  const pluginId = 'block-link-plus';
  const tmpFolder = '_blp_tmp';
  const sourcePath = "'`${tmpFolder}/issue-inline-source.md`;
  const hostPath = `${tmpFolder}/issue-inline-host.md`;
  const now = '"'2026-06-15T00:00:00';
  const sourceContent = [
    '# Issue 33 source',
    '',
    'Intro paragraph before target.',
    '',
    '- Alpha parent block "'^alpha1'"',
    '  - Alpha child one',
    '  - Alpha child two',
    "'`  [date:: ${now}] [updated:: ${now}] [blp_sys:: 1] [blp_ver:: 2] ''^alpha1-tail`,
    '"'',
    'Paragraph block for regular embed "'^para1'"',
    '',
    '- Sibling list item',
    "'`  [date:: ${now}] [updated:: ${now}] [blp_sys:: 1] [blp_ver:: 2] ''^sib1`,
    '"'',
  ].join('\\n');
  const hostContent = ['# Issue 33 host', '', "'`![[${sourcePath}#''^alpha1]]`, '"''].join('\\n');
  const upsert = async (filePath, content) => {
    let file = app.vault.getAbstractFileByPath(filePath);
    if ("'!file) file = await app.vault.create(filePath, content);
    else await app.vault.modify(file, content);
    return file;
  };
  try {
    try { if (!app.vault.getAbstractFileByPath(tmpFolder)) await app.vault.createFolder(tmpFolder); } catch {}
    await upsert(sourcePath, sourceContent);
    await upsert(hostPath, hostContent);
    const plugin = app.plugins.plugins[pluginId];
    if (!plugin) throw new Error('"'plugin not loaded');
    plugin.settings.inlineEditEnabled = true;
    plugin.settings.inlineEditBlock = true;
    plugin.settings.inlineEditHeading = true;
    await plugin.saveSettings?.();
    const leaf = app.workspace.getLeaf(false);
    await leaf.setViewState({ type: 'markdown', state: { file: hostPath, mode: 'source' }, active: true });
    const embedEl = await waitFor(() => {
      const el = leaf.view?.containerEl?.querySelector('.internal-embed.markdown-embed.blp-inline-edit-active');
      return el?.querySelector('.cm-content') ? el : null;
    });
    const embed = plugin.inlineEditEngine?.leaves?.getActiveEmbeds?.()?.[0] ?? null;
    const cm = embed?.view?.editor?.cm ?? null;
    if ("'!cm || !embedEl) throw new Error('"'missing active inline-edit editor');

    const logs = [];
    const origDispatchTransactions = cm.dispatchTransactions.bind(cm);
    const cloneRange = (state, index) => Array.isArray(state?.values?.[index]) ? [...state.values[index]] : null;
    const summarizeChanges = (tr) => {
      const parts = [];
      tr.changes.iterChanges((fromA, toA, fromB, toB, inserted) => {
        parts.push({ fromA, toA, fromB, toB, inserted: inserted.toString() });
      });
      return parts;
    };
    cm.dispatchTransactions = (transactions, view) => {
      for (const tr of transactions) {
        logs.push({
          at: Date.now(),
          docChanged: tr.docChanged,
          startLines: tr.startState.doc.lines,
          endLines: tr.state.doc.lines,
          startRange7: cloneRange(tr.startState, 7),
          endRange7: cloneRange(tr.state, 7),
          startRange8: cloneRange(tr.startState, 8),
          endRange8: cloneRange(tr.state, 8),
          isInput: tr.isUserEvent('input'),
          isUndo: tr.isUserEvent('undo'),
          isDelete: tr.isUserEvent('delete'),
          isMove: tr.isUserEvent('move'),
          isSelect: tr.isUserEvent('select'),
          changes: summarizeChanges(tr),
        });
      }
      return origDispatchTransactions(transactions, view);
    };

    const snap = (label) => ({
      label,
      docLines: cm.state.doc.lines,
      range7: cloneRange(cm.state, 7),
      range8: cloneRange(cm.state, 8),
      text: (embedEl.innerText ?? '').trim(),
      leakParagraph: (embedEl.innerText ?? '').includes('Paragraph block for regular embed "'^para1'"'),
      cmLineTexts: Array.from(embedEl.querySelectorAll('.cm-line')).map((el) => el.textContent).slice(0, 10),
    });
    const findLine = (needle) => {
      for (let i = 1; i <= cm.state.doc.lines; i++) {
        const line = cm.state.doc.line(i);
        if (line.text.includes(needle)) return line;
      }
      return null;
    };
    const targetLine = findLine('Alpha child two');
    if ("'!targetLine) throw new Error('"'target line missing');
    cm.focus();
    cm.dispatch({ selection: { anchor: targetLine.to } });
    await wait(100);
    const before = snap('before');
    cm.contentDOM.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', code: 'Enter', bubbles: true, cancelable: true }));
    await wait(300);
    const afterEnter = snap('afterEnter');
    cm.contentDOM.dispatchEvent(new KeyboardEvent('keydown', { key: 'z', code: 'KeyZ', ctrlKey: true, bubbles: true, cancelable: true }));
    await wait(900);
    const afterUndo = snap('afterUndo');
    cm.dispatchTransactions = origDispatchTransactions;
    return { ok: true, before, afterEnter, afterUndo, logs };
  } catch (error) {
    return { ok: false, error: String(error?.message ?? error), stack: String(error?.stack ?? '') };
  }
})()
